// node_conv_236 - tiled-streaming pointwise (1x1) conv2d.
//   IC=128, OC=512, IH=IW=28, OH=OW=28, SH=SW=1, MP=4.
//   channel_tile=32 -> IN_BEATS=4, OUT_BEATS=16 per pixel.
// Latency: IN_BEATS + OC_PASSES * (MP*K_TOTAL + 6) = 4 + 128*518 = 66308.
module node_conv_236 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);

    localparam integer IC = 128, OC = 512;
    localparam integer IH = 28, IW = 28, OH = 28, OW = 28;
    localparam integer KH = 1, KW = 1;
    localparam integer K_TOTAL = IC * KH * KW;
    localparam integer MP = 4;
    localparam integer OC_PASSES = (OC + MP - 1) / MP;
    localparam integer CHANNEL_TILE = 32;
    localparam integer IN_BEATS  = (IC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam integer OUT_BEATS = (OC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam integer TILE_BITS = CHANNEL_TILE * 8;

    localparam integer SCALE_MULT = 21237;
    localparam integer SCALE_SHIFT = 20;

    localparam integer PROD_W = 16;
    localparam integer ACC_W = PROD_W + 7;
    localparam integer BIAS_W = 32;
    localparam integer BIASED_W = ((ACC_W > BIAS_W) ? ACC_W : BIAS_W) + 1;
    localparam integer SCALE_MAG_W = 15;
    localparam integer SCALE_CONST_W = SCALE_MAG_W + 1;
    localparam integer SCALED_W = BIASED_W + SCALE_CONST_W;

    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};

    (* rom_style="block", ram_style="block" *) reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style="block", ram_style="block" *) reg signed [31:0] biases  [0:OC-1];

    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_236_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_236_bias.hex", biases);
    end

    reg signed [7:0]          in_latch [0:IC-1];
    reg signed [ACC_W-1:0]    acc      [0:MP-1];
    reg signed [BIASED_W-1:0] biased   [0:MP-1];
    reg signed [SCALED_W-1:0] scaled   [0:MP-1];
    reg [OC*8-1:0] out_pack;

    reg signed [7:0] weight_q, act_q;
    (* use_dsp="yes" *) reg signed [PROD_W-1:0] mul_q;
    reg mac_valid_q1, mac_valid_q2;
    reg [2:0] mac_lane_q1, mac_lane_q2;
    reg mac_done_issuing;

    localparam [2:0] ST_LOAD=0, ST_RUNNING=1, ST_BIAS=2, ST_SCALE=3, ST_OUTPUT=4, ST_EMIT=5, ST_DRAIN=6;
    reg [2:0] state;
    reg [2:0] in_beat_idx;
    reg [4:0] out_beat_idx;
    reg [4:0] pixel_row, pixel_col;
    reg [9:0] active_emit_count;
    reg [7:0] oc_group;
    reg [2:0] lane_counter;
    reg [7:0] k_counter;
    reg acc_clr;

    integer i, ch, lane_i, global_oc;
    reg signed [SCALED_W-1:0] v_tmp;

    always @(posedge clk) begin
        if (state == ST_LOAD && valid_in && ready_in) begin
            for (ch = 0; ch < CHANNEL_TILE; ch = ch + 1)
                in_latch[in_beat_idx*CHANNEL_TILE + ch] <= data_in[ch*8 +: 8];
        end
        if (acc_clr) begin
            for (i = 0; i < MP; i = i + 1) acc[i] <= {ACC_W{1'b0}};
        end else if (mac_valid_q2) begin
            acc[mac_lane_q2] <= acc[mac_lane_q2] + mul_q;
        end
        if (state == ST_BIAS) begin
            for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1)
                biased[lane_i] <= acc[lane_i] + biases[oc_group*MP + lane_i];
        end
        if (state == ST_SCALE) begin
            for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1)
                scaled[lane_i] <= biased[lane_i] * SCALE_MULT_CONST;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state<=ST_LOAD; ready_in<=1'b1; valid_out<=1'b0; data_out<=256'd0;
            in_beat_idx<=0; out_beat_idx<=0; pixel_row<=0; pixel_col<=0;
            active_emit_count<=0; oc_group<=0; lane_counter<=0; k_counter<=0;
            mac_valid_q1<=0; mac_valid_q2<=0; mac_lane_q1<=0; mac_lane_q2<=0;
            mac_done_issuing<=0; acc_clr<=0; weight_q<=0; act_q<=0;
            mul_q<=0; out_pack<=0;
        end else begin
            mac_valid_q1 <= 1'b0;
            mac_valid_q2 <= mac_valid_q1;
            mac_lane_q2  <= mac_lane_q1;
            acc_clr      <= 1'b0;
            if (mac_valid_q1) mul_q <= weight_q * act_q;
            case (state)
                ST_LOAD: begin
                    valid_out <= 1'b0;
                    if (valid_in && ready_in) begin
                        if (in_beat_idx == IN_BEATS-1) begin
                            in_beat_idx<=0; ready_in<=1'b0; oc_group<=0;
                            lane_counter<=0; k_counter<=0; mac_done_issuing<=0;
                            acc_clr<=1'b1; state<=ST_RUNNING;
                        end else in_beat_idx <= in_beat_idx + 1;
                    end
                end
                ST_RUNNING: begin
                    if (!mac_done_issuing) begin
                        weight_q     <= weights[(oc_group*MP + lane_counter)*K_TOTAL + k_counter];
                        act_q        <= in_latch[k_counter];
                        mac_valid_q1 <= 1'b1;
                        mac_lane_q1  <= lane_counter;
                        if (k_counter == K_TOTAL-1) begin
                            k_counter <= 0;
                            if (lane_counter == MP-1) begin
                                lane_counter<=0; mac_done_issuing<=1'b1;
                            end else lane_counter <= lane_counter + 1;
                        end else k_counter <= k_counter + 1;
                    end
                    if (mac_done_issuing && !mac_valid_q1 && !mac_valid_q2)
                        state <= ST_BIAS;
                end
                ST_BIAS:  state <= ST_SCALE;
                ST_SCALE: state <= ST_OUTPUT;
                ST_OUTPUT: begin
                    for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1) begin
                        global_oc = oc_group*MP + lane_i;
                        v_tmp = (scaled[lane_i] +
                                 (scaled[lane_i][SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)
                                ) >>> SCALE_SHIFT;
                        out_pack[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 :
                                                       (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                    end
                    if (oc_group == OC_PASSES-1) begin
                        valid_out    <= 1'b1;
                        data_out     <= out_pack[0 +: TILE_BITS];
                        out_beat_idx <= 5'd1;
                        state        <= ST_EMIT;
                    end else begin
                        oc_group<=oc_group+1; lane_counter<=0; k_counter<=0;
                        mac_done_issuing<=0; acc_clr<=1'b1; state<=ST_RUNNING;
                    end
                end
                ST_EMIT: begin
                    valid_out <= 1'b1;
                    data_out  <= out_pack[out_beat_idx*TILE_BITS +: TILE_BITS];
                    if (out_beat_idx == OUT_BEATS-1) begin
                        out_beat_idx<=0;
                        if (active_emit_count == OH*OW-1) begin
                            active_emit_count<=0; pixel_row<=0; pixel_col<=0;
                        end else begin
                            active_emit_count <= active_emit_count + 1;
                            if (pixel_col == OW-1) begin pixel_col<=0; pixel_row<=pixel_row+1; end
                            else pixel_col <= pixel_col + 1;
                        end
                        state <= ST_DRAIN;
                    end else out_beat_idx <= out_beat_idx + 1;
                end
                ST_DRAIN: begin
                    valid_out <= 1'b0;
                    ready_in  <= 1'b1;
                    state     <= ST_LOAD;
                end
                default: state <= ST_LOAD;
            endcase
        end
    end
endmodule
